  1	import { useCallback, useMemo, useState } from 'react';
  2	
  3	import { RESTApi } from '@API/REST.api';
  4	import { I18nNamespace } from '@config/config';
  5	import SkTable from '@core/components/SkTable';
  6	import StatusCell from '@core/components/StatusCell';
  7	import { useWatchedSkupperResource } from '@hooks/useSkupperWatchResource';
  8	import { Connector } from '@interfaces/REST.interfaces';
  9	import { SKColumn, SKComponentProps } from '@interfaces/SkTable.interfaces';
 10	import {
 11	  Button,
 12	  Modal,
 13	  ModalVariant,
 14	  Alert,
 15	  Stack,
 16	  StackItem,
 17	  AlertActionCloseButton,
 18	  DrawerPanelContent,
 19	  DrawerActions,
 20	  DrawerCloseButton,
 21	  DrawerPanelBody,
 22	  DrawerHead,
 23	  Drawer,
 24	  DrawerContent,
 25	  DrawerContentBody,
 26	  Card,
 27	  CardBody
 28	} from '@patternfly/react-core';
 29	import { useMutation } from '@tanstack/react-query';
 30	import { useTranslation } from 'react-i18next';
 31	
 32	import ConnectorDetails from './ConnectorDetails';
 33	import LoadingPage from '../../../core/components/Loading';
 34	import ConnectorForm from '../../components/forms/ConnectorForm';
 35	
 36	const Connectors = function () {
 37	  const { t } = useTranslation(I18nNamespace);
 38	
 39	  const [areDetailsOpen, setAreDetailsOpen] = useState<boolean>(false);
 40	  const [nameSelected, setNameSelected] = useState<string | undefined>();
 41	  const [showAlert, setShowAlert] = useState<string>(sessionStorage.getItem('showConnectorAlert') || 'show');
 42	
 43	  const { data: connectors, loaded } = useWatchedSkupperResource({ kind: 'Connector' });
 44	
 45	  const mutationDelete = useMutation({
 46	    mutationFn: (name: string) => RESTApi.deleteConnector(name),
 47	    onSuccess: () => handleCloseDetails()
 48	  });
 49	
 50	  const handleDelete = useCallback(
 51	    (name: string) => {
 52	      mutationDelete.mutate(name);
 53	    },
 54	    [mutationDelete]
 55	  );
 56	
 57	  const handleModalClose = useCallback(() => {
 58	    setAreDetailsOpen(false);
 59	  }, []);
 60	
 61	  const handleOpenDetails = useCallback((name: string) => {
 62	    setNameSelected(name);
 63	  }, []);
 64	
 65	  const handleCloseDetails = useCallback(() => {
 66	    setNameSelected(undefined);
 67	  }, []);
 68	
 69	  const handleCloseAlert = useCallback(() => {
 70	    setShowAlert('hide');
 71	    sessionStorage.setItem('showConnectorAlert', 'hide');
 72	  }, []);
 73	
 74	  const Columns: SKColumn<Connector>[] = [
 75	    {
 76	      name: t('Name'),
 77	      prop: 'name',
 78	      customCellName: 'linkCell'
 79	    },
 80	    {
 81	      name: t('Status'),
 82	      prop: 'status',
 83	      customCellName: 'StatusCell'
 84	    },
 85	    {
 86	      name: t('Message'),
 87	      prop: 'statusMessage'
 88	    },
 89	    {
 90	      name: t('Routing key'),
 91	      prop: 'routingKey'
 92	    },
 93	    {
 94	      name: t('Selector'),
 95	      prop: 'selector'
 96	    },
 97	    {
 98	      name: t('Host'),
 99	      prop: 'host'
100	    },
101	    {
102	      name: t('Port'),
103	      prop: 'port'
104	    },
105	    {
106	      name: t('Has listeners'),
107	      prop: 'connected',
108	      customCellName: 'connectedCell'
109	    },
110	    {
111	      name: '',
112	      customCellName: 'actions',
113	      modifier: 'fitContent'
114	    }
115	  ];
116	
117	  const customCells = useMemo(
118	    () => ({
119	      linkCell: ({ data }: SKComponentProps<Connector>) => (
120	        <Button variant="link" onClick={handleOpenDetails.bind(null, data.name)}>
121	          {data.name}
122	        </Button>
123	      ),
124	      StatusCell,
125	      connectedCell: ({ data }: SKComponentProps<Connector>) => `${data.connected}`,
126	      actions: ({ data }: SKComponentProps<Connector>) => (
127	        <Button onClick={handleDelete.bind(null, data.name)} variant="link">
128	          {t('Delete')}
129	        </Button>
130	      )
131	    }),
132	    [handleDelete, handleOpenDetails, t]
133	  );
134	
135	  const panelContent = (
136	    <DrawerPanelContent isResizable minSize="30%">
137	      <DrawerHead>
138	        <DrawerActions>
139	          <DrawerCloseButton onClick={handleCloseDetails} />
140	        </DrawerActions>
141	      </DrawerHead>
142	      <DrawerPanelBody>
143	        {nameSelected && <ConnectorDetails name={nameSelected} onUpdate={handleModalClose} />}
144	      </DrawerPanelBody>
145	    </DrawerPanelContent>
146	  );
147	
148	  if (!loaded) {
149	    return <LoadingPage />;
150	  }
151	
152	  return (
153	    <Card isPlain isFullHeight>
154	      <CardBody>
155	        <Stack hasGutter>
156	          <StackItem>
157	            {showAlert === 'show' && (
158	              <Alert
159	                data-testid="connector-alert"
160	                hidden={true}
161	                variant="info"
162	                actionClose={<AlertActionCloseButton onClose={handleCloseAlert} data-testid="connector-alert-close" />}
163	                isInline
164	                title={t(
165	                  'A connector binds local servers (pods, containers, or processes) to connection listeners in remote sites. Connectors are linked to listeners by a matching routing key.'
166	                )}
167	              />
168	            )}
169	          </StackItem>
170	
171	          <StackItem isFilled>
172	            <Button onClick={() => setAreDetailsOpen(true)}>{t('Create a connector')}</Button>{' '}
173	            <Drawer isExpanded={!!nameSelected} isInline>
174	              <DrawerContent panelContent={panelContent}>
175	                <DrawerContentBody>
176	                  <SkTable
177	                    columns={Columns}
178	                    rows={connectors || []}
179	                    alwaysShowPagination={false}
180	                    customCells={customCells}
181	                    isPlain
182	                  />
183	                </DrawerContentBody>
184	              </DrawerContent>
185	            </Drawer>
186	          </StackItem>
187	        </Stack>
188	
189	        <Modal
190	          hasNoBodyWrapper
191	          isOpen={areDetailsOpen}
192	          variant={ModalVariant.medium}
193	          aria-label="Form create connector"
194	          showClose={false}
195	        >
196	          <ConnectorForm onSubmit={handleModalClose} onCancel={handleModalClose} title={t('Create a Connector')} />
197	        </Modal>
198	      </CardBody>
199	    </Card>
200	  );
201	};
202	
203	export default Connectors;

